/* eslint-disable security/detect-non-literal-regexp */
const { SPECIFIC_DEVICE_TYPES } = require('./device');
const {
  HOOKS_FILE_IDENTIFIER,
  SCRIPT_OPTIONS,
  STYLES_OPTIONS,
  SCRIPT_EXTENSIONS,
  STYLE_EXTENSIONS,
} = require('./file');
const {
  SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS,
  STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS,
  NORDIC_PAGES_PATH,
} = require('./files-discovery');

const deviceTypeNaming = Object.keys(SPECIFIC_DEVICE_TYPES).join('|');
const fileExtensionNaming = [...SCRIPT_EXTENSIONS, ...STYLE_EXTENSIONS].join(
  '|',
);

/**
 * Used in normalizeIslandClientName( to match script extensions.
 * This regex matches the file extension when it is a SCRIPT.
 * @examples
 * .js
 * .tsx
 */
const SCRIPT_EXTENSIONS_REGEX = new RegExp(
  `(\\.${SCRIPT_EXTENSIONS.join('|\\.')})`,
);

/**
 * Used in checkIfViewOrStyles(file) to match VIEW files.
 * This regex matches when the file has a SCRIPT extension and is not a HOOKS file.
 * @example
 * /items/[id].js
 */
const VIEW_REGEX = new RegExp(
  `^(?!(.*((\\.${HOOKS_FILE_IDENTIFIER.VIEW_SPECIFIC})|${HOOKS_FILE_IDENTIFIER.BASE})\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})))(.*\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}))$`,
);

/**
 * Used in checkIfViewOrStyles(file) to match STYLE SHEETS files.
 * This regex matches when the file has a STYLE extension.
 * @example
 * /items/[id].css
 */
const STYLES_REGEX = new RegExp(
  `.*\\.(${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in getTheFileNamingConvention(file) to match PAGE-SPECIFIC SERVER HOOKS files.
 * This regex matches when the file is a
 * PAGE-SPECIFIC SERVER HOOKS (*.hooks.server.<scriptExtension>)
 * @example
 * /items/[id].hooks.server.js
 */
const PAGE_HOOKS_REGEX = new RegExp(
  `.*\\.${HOOKS_FILE_IDENTIFIER.VIEW_SPECIFIC}(\\.(${deviceTypeNaming}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in getTheFileNamingConvention(file) to match BASE HOOKS files.
 * This regex matches when the file is a BASE HOOKS (_hooks.server.<scriptExtension>).
 * @example
 * /items/_hooks.server.ts
 */
const BASE_HOOKS_NAMING_REGEX = new RegExp(
  `((^)|(.*\\/))?${HOOKS_FILE_IDENTIFIER.BASE}(\\.(${deviceTypeNaming}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in getTheFileNamingConvention(file) to match ROUTER CONFIG files (_router.config.<scriptExtension>).
 * @example
 * /items/_router.config.ts
 */
const ROUTER_CONFIG_NAMING_REGEX = new RegExp(
  `(?:^|.*\\/)_router\\.config\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in compareToSortFilesByOwnerAndPage(a, b) and getFileType(file) to match HTTP ERRORS files
 * in the pages directory.
 * This regex matches when the file is located in the nordic pages directory root
 * and follows the HTTP ERROR status code naming convention.
 * @example
 * 404.js, 404.mobile.scss, 5xx/index.js
 */
const indexScriptNaming = `index(\\.(${deviceTypeNaming}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})`;
const indexStyleNaming = `(index|styles)(\\.(${deviceTypeNaming}))?\\.(${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})`;
const HTTP_ERROR_PAGE_FILES_IN_ROOT_REGEX = new RegExp(
  '^(404|5xx)' +
    `((\\/((${indexScriptNaming})|(${indexStyleNaming})))` +
    `|((\\.(${deviceTypeNaming}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}|${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})))$`,
);

/**
 * Used in classifyDiscoveredFiles(discoveredFiles, dir) to match root files
 * in the root directory of the pages.
 * This regex matches when the file is located in root.
 * @example
 * _hooks.server.ts
 */
const FILE_IN_ROOT_REGEX = new RegExp(
  `^([A-Z]|[a-z]|_|\\-|\\.)+\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in getDeviceTypeOfFile(file) to get the DEVICE TYPE of the file (if any).
 * This regex matches when the file is a DEVICE TYPE VIEW or a DEVICE TYPE STYLE sheet.
 * @example
 * index.mobile.js
 * home.mobile.scss
 */
const FILE_WITH_DEVICE_SPECIFIED_REGEX = new RegExp(
  `.*\\.(${deviceTypeNaming})\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}|${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in getDeviceTypeOfFile(file) to get the DEVICE TYPE of a file.
 * This regex matches when the file has a DEVICE TYPE.
 * @example
 * mobile
 */
const DEVICE_TYPE_REGEX = new RegExp(`^(${deviceTypeNaming})$`);

const FILE_EXTENSION_REGEX = new RegExp(`.+\\.(${fileExtensionNaming})$`);

const DEVICE_WITH_EXTENSION_PATTERN = `(?:\\.(?:${deviceTypeNaming}|hooks\\.server))?\\.(?:${fileExtensionNaming})`;

const PARAMS_PATTERN = '^\\[([^[\\]\\s]+)\\]';

/**
 * Used in normalizePathToExpressRoute(navigablePageFile) to normalize the paths containing PARAMS to Express ROUTES.
 * This regex matches when the folder name is a path with PARAMS.
 * @example
 * [id]
 */
const FOLDER_WITH_PARAMS_REGEX = new RegExp(`${PARAMS_PATTERN}$`);

/**
 * Used in normalizePathToExpressRoute(navigablePageFile) to normalize the paths containing PARAMS to Express ROUTES.
 * This regex matches when the file name is a path with PARAMS.
 * @example
 * [id].js
 * [id].desktop.js
 */
const FILE_WITH_PARAMS_REGEX = new RegExp(
  `${PARAMS_PATTERN}${DEVICE_WITH_EXTENSION_PATTERN}$`,
);

const CATCH_ALL_PATTERN = `^\\[(?:\\[\\.\\.\\.([^[\\]\\s]+)\\]|\\.\\.\\.([^[\\]\\s]+))\\]`;

/**
 * Used in compareToSortFilesByOwnerAndPage(a,b) to sort the catch-all ROUTES after all other ROUTES.
 * This regex matches when the folder name is a catch-all ROUTE.
 * @example
 * [...param]
 * [[...param]]
 */
const FOLDER_WITH_CATCH_ALL_REGEX = new RegExp(`${CATCH_ALL_PATTERN}$`);

/**
 * Used in compareToSortFilesByOwnerAndPage(a,b) to sort the catch-all ROUTES after all other ROUTES.
 * This regex matches when the file name is a catch-all ROUTE.
 * @example
 * [...param].js
 * [[...param]].js
 * [...param].desktop.js
 * [[...param]].desktop.js
 */
const FILE_WITH_CATCH_ALL_REGEX = new RegExp(
  `${CATCH_ALL_PATTERN}${DEVICE_WITH_EXTENSION_PATTERN}$`,
);

/**
 * Used in compareToSortFilesByOwnerAndPage(a,b), compareToSortFilesByOwnerAndPage(a,b) and normalizePathToPageDataId(navigablePageFile) to remove naming conventions from the file path
 * in order to sort the discovered files.
 * This regex matches when the file has DEVICE TYPE, VIEW, STYLE or
 * PAGE-SPECIFIC HOOKS naming convention.
 * @example
 * home.mobile.js => home
 * home.hooks.server.js => home
 */
const BASENAME_REGEX = new RegExp(
  '(' +
    `((\\.(${deviceTypeNaming}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}|${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS}))|` +
    `((\\.${HOOKS_FILE_IDENTIFIER.VIEW_SPECIFIC})\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}))` +
    '$)',
  'g',
);

/**
 * Used in normalizeClientName(client) to remove script or style extensions
 * from the file path to define the client name.
 * This regex matches when the file has a SCRIPT or STYLE extension
 * @example
 * .js, .ts, .jsx, .tsx, .css, .scss
 */
const SCRIPT_OR_STYLES_EXTENSIONS_REGEX = new RegExp(
  `\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}|${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in normalizePathToPageDataId = (navigablePageFile) to replace 'index' with '/'
 * to define the page data id.
 * This regex matches when the string received is 'index'.
 */
const STARTS_WITH_INDEX_REGEX = /^\/index$/;

/**
 * Used in normalizeClientName(client) to replace 'styles' with 'index'
 * from the file path to define the client name.
 * This regex matches when the file name is 'styles'.
 */
const STARTS_WITH_STYLES_REGEX = /^styles$/;

/**
 * Used in normalizeClientName(client) to replace 'styles.' with 'index.'
 * from the file path to define the client name.
 * This regex matches when the file name is 'styles.' for specific device styles.
 * @example
 * styles.desktop
 */
const STARTS_WITH_STYLES_DEVICE_REGEX = /^styles\./;

/**
 * Used in normalizeClientName(client) to replace '/styles' with '/index'
 * from the file path to define the client name.
 * This regex matches when the file name is '/styles'.
 * @example
 * item/styles
 */
const ENDS_WITH_STYLES_REGEX = /\/styles$/;

/**
 * Used in normalizeClientName(client) to replace '/styles.' with '/index.'
 * from the file path to define the client name.
 * This regex matches when the file name is '/styles.' for specific device styles.
 * @example
 * item/styles
 */
const ENDS_WITH_STYLES_DEVICE_REGEX = /\/styles\./;

/**
 * Used in completeBaseObject({}) to remove DEVICE TYPE from the file
 * path to define the base client name.
 * This regex matches when the file name ends with a DEVICE TYPE.
 * @example
 * item/home.desktop
 */
const ENDS_WITH_DEVICE_TYPE_REGEX = new RegExp(`\\.(${deviceTypeNaming})$`);

/**
 * Used in fsRoute(dir, options) to remove the naming convention
 * from the file discovered to define the express route.
 * This regex matches when the file has DEVICE TYPE, VIEW, STYLE or
 * PAGE-SPECIFIC HOOKS naming convention.
 * @example
 * home.js, home.mobile.js, home.hooks.server.jsx => home
 */
const FILE_TO_ROUTE_REGEX = new RegExp(
  `(^(index|styles))?(\\.(${deviceTypeNaming}|${HOOKS_FILE_IDENTIFIER.VIEW_SPECIFIC}))?\\.(${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS}|${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in compare(a, b) to look for index view files in app/nordic-pages root.
 * @example
 * index.js, index.tsx
 */
const INDEX_VIEW_FILE_REGEX = new RegExp(
  `^index\\.(?:${SCRIPT_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in compare(a, b) to look for index style sheet files in app/nordic-pages root.
 * @example
 * index.scss, styles.css
 */
const INDEX_STYLE_SHEET_FILE_REGEX = new RegExp(
  `^(?:index|styles)\\.(?:${STYLE_FILES_TO_DISCOVER_BY_EXTENSIONS})$`,
);

/**
 * Used in fsRoute(dir, options) to remove the naming index convention from the express route.
 * This regex matches when the express route has INDEX naming convention.
 * @example
 * home/index, home/styles => home
 */
const INDEX_FILE_TO_ROUTE_REGEX = /\/(index|styles)$/;

/**
 * Used in fsRoute(dir, options) to discover SCRIPT and STYLE files.
 * This glob matches when the file has SCRIPT or STYLE extension and
 * ignore TEST files
 * @example
 * home.js, /home/index.ts, home.hooks.server.jsx, styles.css, _hooks.server.js
 */
const FILE_EXTENSIONS_TO_DISCOVER_REGEX = `**/!(*\\.spec)\\.{${SCRIPT_OPTIONS},${STYLES_OPTIONS}}`;

/**
 * Used in the islands discovery process to discover app files imported in a file
 */
const RELATIVE_PATH_REGEX = /\.\.?\//;

const ROOT_FILE_REGEX = /^\/$/;

/**
 * Used in normalizePathToPageDataId(navigablePageFile) to normalize absolute paths to paths relative to nordic-pages folder
 */
const NORDIC_PAGE_ABSOLUTE_PATH_TO_RELATIVE_REGEX = new RegExp(
  `.*${NORDIC_PAGES_PATH}/`,
);

/**
 * Used in the islands discovery process to detect Node.js subpath imports
 * @example
 * #components/Button
 * #services/demo
 */
const NODE_SUBPATH_IMPORT_REGEX = /^#/;

module.exports = {
  SCRIPT_EXTENSIONS_REGEX,
  VIEW_REGEX,
  STYLES_REGEX,
  PAGE_HOOKS_REGEX,
  BASE_HOOKS_NAMING_REGEX,
  ROUTER_CONFIG_NAMING_REGEX,
  FILE_IN_ROOT_REGEX,
  HTTP_ERROR_PAGE_FILES_IN_ROOT_REGEX,
  FILE_EXTENSION_REGEX,
  FOLDER_WITH_PARAMS_REGEX,
  FILE_WITH_PARAMS_REGEX,
  FOLDER_WITH_CATCH_ALL_REGEX,
  FILE_WITH_CATCH_ALL_REGEX,
  FILE_WITH_DEVICE_SPECIFIED_REGEX,
  DEVICE_TYPE_REGEX,
  BASENAME_REGEX,
  SCRIPT_OR_STYLES_EXTENSIONS_REGEX,
  STARTS_WITH_STYLES_DEVICE_REGEX,
  STARTS_WITH_INDEX_REGEX,
  STARTS_WITH_STYLES_REGEX,
  ENDS_WITH_STYLES_REGEX,
  ENDS_WITH_STYLES_DEVICE_REGEX,
  ENDS_WITH_DEVICE_TYPE_REGEX,
  FILE_TO_ROUTE_REGEX,
  INDEX_VIEW_FILE_REGEX,
  INDEX_STYLE_SHEET_FILE_REGEX,
  INDEX_FILE_TO_ROUTE_REGEX,
  FILE_EXTENSIONS_TO_DISCOVER_REGEX,
  RELATIVE_PATH_REGEX,
  ROOT_FILE_REGEX,
  NORDIC_PAGE_ABSOLUTE_PATH_TO_RELATIVE_REGEX,
  NODE_SUBPATH_IMPORT_REGEX,
};
